const body = $input.first().json.body || $input.first().json;
const sale_id = body.sale_id || body.id || '';
const email = body.email || body.purchaser_email || '';
const product = body.product_name || body.short_url || 'unknown';
const price = body.price || body.sale_price || 0;
const is_free = price === 0 || price === '0';
return [{
  json: {
    sale_id,
    email,
    product_name: product,
    price,
    is_free,
    event_type: is_free ? 'lead_magnet_download' : 'sale',
    timestamp: new Date().toISOString()
  }
}];
